from langgraph.graph import StateGraph, END
from langchain_anthropic import ChatAnthropic
from typing import TypedDict, Annotated
import operator

haiku = ChatAnthropic(model="claude-haiku-4-5-20251001")
sonnet = ChatAnthropic(model="claude-sonnet-5")

# --- Research Team ---

class ResearchTeamState(TypedDict):
    topic: str
    web_results: str
    doc_contents: str
    summary: str
    errors: Annotated[list[str], operator.add]
    next: str

RESEARCH_WORKERS = ["web_searcher", "doc_reader", "FINISH"]

def research_lead_node(state: ResearchTeamState) -> dict:
    done_flags = {
        "web_searcher": bool(state["web_results"]),
        "doc_reader":   bool(state["doc_contents"]),
    }
    pending = [w for w, done in done_flags.items() if not done]
    choice = pending[0] if pending else "FINISH"
    return {"next": choice}

def web_searcher_node(state: ResearchTeamState) -> dict:
    try:
        resp = haiku.invoke([
            {"role": "system", "content": "Search and summarise web results for the given topic."},
            {"role": "user",   "content": state["topic"]},
        ])
        return {"web_results": resp.content}
    except Exception as exc:
        return {"web_results": "", "errors": [f"web_searcher:{exc}"]}

def doc_reader_node(state: ResearchTeamState) -> dict:
    try:
        resp = haiku.invoke([
            {"role": "system", "content": "Find and summarise relevant document content for the given topic."},
            {"role": "user",   "content": state["topic"]},
        ])
        return {"doc_contents": resp.content}
    except Exception as exc:
        return {"doc_contents": "", "errors": [f"doc_reader:{exc}"]}

def route_research(state: ResearchTeamState):
    return state["next"] if state["next"] != "FINISH" else END

def build_research_team():
    sg = StateGraph(ResearchTeamState)
    sg.add_node("lead",        research_lead_node)
    sg.add_node("web_searcher", web_searcher_node)
    sg.add_node("doc_reader",   doc_reader_node)
    sg.set_entry_point("lead")
    sg.add_conditional_edges("lead", route_research,
        {"web_searcher": "web_searcher", "doc_reader": "doc_reader", END: END})
    sg.add_edge("web_searcher", "lead")
    sg.add_edge("doc_reader",   "lead")
    return sg.compile()

class CoordinatorState(TypedDict):
    task: str
    research_done: bool
    analysis_done: bool
    research_output: str
    analysis_output: str
    final: str
    errors: Annotated[list[str], operator.add]
    next: str

research_team  = build_research_team()
# analysis_team and writing_team built similarly

TEAMS = ["research_team", "analysis_team", "FINISH"]

def executive_node(state: CoordinatorState) -> dict:
    if not state["research_done"]:
        return {"next": "research_team"}
    if not state["analysis_done"]:
        return {"next": "analysis_team"}
    return {"next": "FINISH"}

def call_research_team(state: CoordinatorState) -> dict:
    result = research_team.invoke({
        "topic": state["task"],
        "web_results": "", "doc_contents": "", "summary": "",
        "errors": [], "next": "",
    })
    errors = result.get("errors", [])
    return {
        "research_output": result.get("web_results", "") + result.get("doc_contents", ""),
        "research_done": True,
        "errors": errors,
    }

def synthesize_final(state: CoordinatorState) -> dict:
    resp = sonnet.invoke([
        {"role": "system", "content": "Synthesise research and analysis into a final report."},
        {"role": "user", "content": (
            f"Task: {state['task']}\n"
            f"Research: {state['research_output']}\n"
            f"Analysis: {state['analysis_output']}"
        )},
    ])
    return {"final": resp.content}

def route_coordinator(state: CoordinatorState):
    mapping = {
        "research_team": "research_team",
        "analysis_team": "analysis_team",
        "FINISH": "synthesize",
    }
    return mapping[state["next"]]

def build_coordinator():
    builder = StateGraph(CoordinatorState)
    builder.add_node("executive",     executive_node)
    builder.add_node("research_team", call_research_team)
    builder.add_node("synthesize",    synthesize_final)
    builder.set_entry_point("executive")
    builder.add_conditional_edges("executive", route_coordinator,
        {"research_team": "research_team", "synthesize": "synthesize"})
    builder.add_edge("research_team", "executive")
    builder.add_edge("synthesize", END)
    return builder.compile()

from langgraph.types import Send

class ParallelCoordinatorState(TypedDict):
    task: str
    team_results: Annotated[list[dict], operator.add]
    final: str
    errors: Annotated[list[str], operator.add]

class TeamInvocation(TypedDict):
    team_name: str
    team_input: dict

def dispatch_all_teams(state: ParallelCoordinatorState) -> list[Send]:
    """Fan out all teams simultaneously."""
    return [
        Send("run_team", {
            "team_name": "research",
            "team_input": {"topic": state["task"], "web_results": "", "doc_contents": "",
                           "summary": "", "errors": [], "next": ""},
        }),
        Send("run_team", {
            "team_name": "analysis",
            "team_input": {"topic": state["task"], "data": "", "insights": "",
                           "errors": [], "next": ""},
        }),
    ]

TEAM_GRAPHS = {
    "research": build_research_team(),
    # "analysis": build_analysis_team(),
}

def run_team_node(state: TeamInvocation) -> dict:
    """Generic node: invokes the appropriate team subgraph."""
    graph = TEAM_GRAPHS.get(state["team_name"])
    if graph is None:
        return {"team_results": [{"team": state["team_name"], "output": "", "error": "unknown_team"}]}
    try:
        result = graph.invoke(state["team_input"])
        output = result.get("web_results", "") + result.get("doc_contents", "")
        return {"team_results": [{"team": state["team_name"], "output": output, "error": None}]}
    except Exception as exc:
        return {"team_results": [{"team": state["team_name"], "output": "", "error": str(exc)}]}

def parallel_synthesize(state: ParallelCoordinatorState) -> dict:
    sections = [
        f"""## {r['team'].title()} Team\n{r['output']}"""
        for r in state["team_results"] if r.get("output")
    ]
    resp = sonnet.invoke([
        {"role": "user", "content": f"Task: {state['task']}\n\n" + "\n\n".join(sections)},
    ])
    return {"final": resp.content}

def parallel_synthesize_lenient(state: ParallelCoordinatorState) -> dict:
    """Synthesize from successful teams only; surface failures in output."""
    good  = [r for r in state["team_results"] if not r.get("error")]
    failed = [r["team"] for r in state["team_results"] if r.get("error")]

    if not good:
        return {"final": "", "errors": ["synthesize:all_teams_failed"]}

    sections = [
        f"## {r['team'].title()} Team\n{r['output']}"
        for r in good
    ]
    note = (f"Note: {failed} team(s) did not complete." if failed else "")
    resp = sonnet.invoke([
        {"role": "system", "content": "Synthesise the available team outputs into a final report. " + note},
        {"role": "user",   "content": "\n\n".join(sections)},
    ])
    errors = [f"team:{t}:failed" for t in failed]
    return {"final": resp.content, "errors": errors}
